
"use client"

import { useState, useEffect } from "react";
import { useRouter } from "next/navigation";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Dialog, DialogContent, DialogTitle, DialogDescription, DialogHeader } from "@/components/ui/dialog";
import {
  Loader2, Timer, Trophy, RotateCcw, MapPin, Gauge, Zap, Navigation, ChevronRight
} from "lucide-react";
import { cn } from "@/lib/utils";
import { useToast } from "@/hooks/use-toast";
import { useUser, useDoc, useFirestore, useMemoFirebase, addDocumentNonBlocking } from "@/firebase";
import { doc, collection } from "firebase/firestore";
import { useDriving } from "@/context/driving-context";
import dynamic from "next/dynamic";

const RouteMap = dynamic(() => import("@/components/telemetry/route-map"), { 
  ssr: false,
  loading: () => <div className="w-full h-full bg-black rounded-[2rem] animate-pulse" />
});

export default function DashboardPage() {
  const router = useRouter();
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const {
    speed, isDriving, peakSpeed, tripTime, tripDistance,
    routePoints, startTrip, stopTrip, resetTrip, requestWakeLock
  } = useDriving();

  const [mounted, setMounted] = useState(false);
  const [showSummary, setShowSummary] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [activeModule, setActiveModule] = useState<'top-speed' | 'drag' | 'nav'>('top-speed');
  
  const { toast } = useToast();

  const profileRef = useMemoFirebase(() => {
    if (!user?.uid || isUserLoading || !db) return null;
    return doc(db, "users", user.uid);
  }, [user?.uid, isUserLoading, db]);
  const { data: profile } = useDoc(profileRef);

  useEffect(() => {
    setMounted(true);
  }, []);

  const handleStartMission = () => {
    startTrip();
    requestWakeLock();
  };

  const handleStopMission = () => {
    setShowSummary(true);
    stopTrip();
  };

  const handleSaveRun = () => {
    if (!user?.uid || !db || !profile) return;
    setIsSaving(true);
    const runData = {
      userId: user.uid,
      username: profile.username,
      carBrand: profile.carBrand,
      carModel: profile.carModel,
      profileIcon: profile.profileIcon,
      city: profile.city || "Kosovë",
      runType: activeModule === 'top-speed' ? 'Top Speed' : 'Drag',
      durationSeconds: tripTime,
      peakSpeedKmH: peakSpeed,
      distanceMeters: tripDistance,
      createdAt: new Date().toISOString(),
      updatedAt: new Date().toISOString(),
      carProfileId: "primary"
    };

    addDocumentNonBlocking(collection(db, "users", user.uid, "runs"), runData);
    addDocumentNonBlocking(collection(db, "public_runs"), runData);

    toast({ title: "REKORD I RI!", description: "Gara u ruajt me sukses." });
    setIsSaving(false);
    setShowSummary(false);
    resetTrip();
  };

  if (!mounted || isUserLoading) return <div className="min-h-screen bg-black flex items-center justify-center"><Loader2 className="w-8 h-8 animate-spin text-red-500" /></div>;

  // Gauge Constants
  const size = 360;
  const radius = 150;
  const center = size / 2;
  
  // RPM Mapping: 0-8. Speed 0-240 maps to 0-8.
  const rpmValue = Math.min((speed / 240) * 8, 8);
  const startAngle = 135;
  const endAngle = 405;
  const totalAngle = endAngle - startAngle;
  const currentAngle = startAngle + (rpmValue / 8) * totalAngle;

  return (
    <div className="flex flex-col min-h-screen text-white pb-24 overflow-x-hidden safe-top relative bg-black">
      
      {/* Professional Gradient Overlay (Full Opacity) */}
      <div className="absolute inset-0 bg-gradient-to-b from-black via-zinc-950 to-red-950 pointer-events-none z-0" />

      <div className="flex-1 flex flex-col items-center justify-center p-6 relative z-10">
        
        {/* Module Selector - Top Navigation */}
        <div className="flex gap-2 mb-10 bg-white/5 p-1.5 rounded-2xl border border-white/5 backdrop-blur-xl">
          <button 
            onClick={() => setActiveModule('top-speed')}
            className={cn(
              "px-4 py-2 rounded-xl font-black text-[9px] uppercase tracking-widest transition-all flex items-center gap-2",
              activeModule === 'top-speed' ? "bg-white text-black" : "text-white/40 hover:text-white"
            )}
          >
            <Gauge className="w-3.5 h-3.5" /> TOP SPEED
          </button>
          <button 
            onClick={() => setActiveModule('drag')}
            className={cn(
              "px-4 py-2 rounded-xl font-black text-[9px] uppercase tracking-widest transition-all flex items-center gap-2",
              activeModule === 'drag' ? "bg-accent text-background" : "text-white/40 hover:text-white"
            )}
          >
            <Zap className="w-3.5 h-3.5" /> DRAG
          </button>
          <button 
            onClick={() => setActiveModule('nav')}
            className={cn(
              "px-4 py-2 rounded-xl font-black text-[9px] uppercase tracking-widest transition-all flex items-center gap-2",
              activeModule === 'nav' ? "bg-blue-500 text-white" : "text-white/40 hover:text-white"
            )}
          >
            <Navigation className="w-3.5 h-3.5" /> NAV
          </button>
        </div>

        {/* The RPM-Style Gauge */}
        <div className="relative w-[360px] h-[360px] flex items-center justify-center">
          
          <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`} className="drop-shadow-[0_0_20px_rgba(255,255,255,0.05)]">
            {/* Ticks & Numbers */}
            {Array.from({ length: 81 }).map((_, i) => {
              const val = i / 10;
              const angle = startAngle + (val / 8) * totalAngle;
              const isMajor = i % 10 === 0;
              const isRedline = val >= 6;
              
              const x1 = center + (radius - (isMajor ? 15 : 8)) * Math.cos((angle * Math.PI) / 180);
              const y1 = center + (radius - (isMajor ? 15 : 8)) * Math.sin((angle * Math.PI) / 180);
              const x2 = center + radius * Math.cos((angle * Math.PI) / 180);
              const y2 = center + radius * Math.sin((angle * Math.PI) / 180);

              return (
                <g key={i}>
                  <line
                    x1={x1} y1={y1} x2={x2} y2={y2}
                    stroke={isRedline ? "#ef4444" : "rgba(255,255,255,0.3)"}
                    strokeWidth={isMajor ? 2 : 1}
                  />
                  {isMajor && (
                    <text
                      x={center + (radius - 40) * Math.cos((angle * Math.PI) / 180)}
                      y={center + (radius - 40) * Math.sin((angle * Math.PI) / 180)}
                      fill={isRedline ? "#ef4444" : "white"}
                      fontSize="28"
                      fontWeight="300"
                      textAnchor="middle"
                      alignmentBaseline="middle"
                    >
                      {val}
                    </text>
                  )}
                </g>
              );
            })}

            {/* Red Needle */}
            <line
              x1={center + (radius - 120) * Math.cos((currentAngle * Math.PI) / 180)}
              y1={center + (radius - 120) * Math.sin((currentAngle * Math.PI) / 180)}
              x2={center + (radius - 10) * Math.cos((currentAngle * Math.PI) / 180)}
              y2={center + (radius - 10) * Math.sin((currentAngle * Math.PI) / 180)}
              stroke="#ef4444"
              strokeWidth="4"
              strokeLinecap="round"
              className="transition-all duration-75 ease-linear"
            />
            
            {/* Gear Indicator */}
            <text x={center + 100} y={center + 100} fill="white" fontSize="24" fontWeight="300" className="opacity-80">
              {speed > 0 ? "D" : "P"}
            </text>

            {/* Bottom Label */}
            <text x={center} y={center + 140} fill="white" fontSize="10" textAnchor="middle" className="opacity-40 font-bold tracking-widest uppercase">
              /min x1000
            </text>
          </svg>

          {/* Central Speed Display */}
          <div className="absolute inset-0 flex flex-col items-center justify-center">
             <div className="relative">
                {/* Brackets [ ] */}
                <div className="absolute -left-10 -top-4 text-4xl font-light opacity-20 text-white">[</div>
                <div className="absolute -right-10 -top-4 text-4xl font-light opacity-20 text-white">]</div>
                
                <div className="flex flex-col items-center">
                  <span className="text-8xl font-bold tracking-tighter tabular-nums leading-none text-white drop-shadow-[0_0_15px_rgba(255,255,255,0.2)]">
                    {speed}
                  </span>
                  <span className="text-sm font-light text-white/40 uppercase tracking-widest mt-2">km/h</span>
                </div>
             </div>
          </div>
        </div>

        {/* Essential Telemetry Stats */}
        <div className="w-full max-w-[340px] grid grid-cols-2 gap-4 mt-12">
          <div className="bg-white/5 border border-white/5 p-4 rounded-3xl flex flex-col items-center backdrop-blur-md">
            <Timer className="w-4 h-4 text-white/20 mb-2" />
            <span className="text-[8px] font-bold uppercase text-white/40 tracking-widest">SESSION TIME</span>
            <span className="text-lg font-light tabular-nums">{tripTime.toFixed(1)}s</span>
          </div>
          <div className="bg-white/5 border border-white/5 p-4 rounded-3xl flex flex-col items-center backdrop-blur-md">
            <Trophy className="w-4 h-4 text-white/20 mb-2" />
            <span className="text-[8px] font-bold uppercase text-white/40 tracking-widest">PEAK SPEED</span>
            <span className="text-lg font-light tabular-nums text-red-500">{peakSpeed} <span className="text-[10px]">km/h</span></span>
          </div>
        </div>

        {/* Action Button */}
        <div className="w-full max-w-[340px] mt-8">
           <Button
             onClick={isDriving ? handleStopMission : handleStartMission}
             className={cn(
               "w-full h-16 rounded-3xl font-black text-sm uppercase tracking-widest transition-all shadow-lg",
               isDriving 
                ? "bg-red-600 text-white hover:bg-red-700 shadow-red-600/20" 
                : "bg-accent text-background hover:bg-accent/90 shadow-accent/20"
             )}
           >
             {isDriving ? (
               <div className="flex items-center gap-2">
                 <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                   <rect x="4" y="4" width="16" height="16" />
                 </svg>
                 Stop Trip
               </div>
             ) : (
               <div className="flex items-center gap-2">
                 <svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                   <path d="M5 3l14 9-14 9V3z" />
                 </svg>
                 Start Trip
               </div>
             )}
           </Button>
           
           {isDriving && (
             <Button 
               variant="ghost" 
               onClick={resetTrip}
               className="w-full mt-4 h-10 rounded-2xl font-black text-[10px] uppercase tracking-widest text-zinc-600 hover:text-white"
             >
               <RotateCcw className="w-3 mr-2" /> RESET TELEMETRY
             </Button>
           )}
        </div>
      </div>

      {/* Result Summary Dialog */}
      <Dialog open={showSummary} onOpenChange={setShowSummary}>
        <DialogContent className="bg-zinc-950 border-white/10 w-[94%] max-w-sm rounded-[2.5rem] p-8">
          <DialogHeader>
            <DialogTitle className="text-2xl font-black italic tracking-tighter text-center uppercase">REZULTATI</DialogTitle>
            <DialogDescription className="text-[10px] font-bold text-muted-foreground uppercase tracking-widest mt-2 text-center">
              DRIVING SESSION SUMMARY
            </DialogDescription>
          </DialogHeader>

          <div className="space-y-6 mt-4">
            <div className="bg-white/5 p-8 rounded-[2rem] border border-white/5 text-center">
              <span className="text-6xl font-black text-white italic tabular-nums leading-none">
                {peakSpeed}
              </span>
              <span className="text-xl font-black text-red-600 ml-2 italic">
                km/h
              </span>
              
              <div className="mt-4 flex items-center justify-center gap-2 text-[10px] font-black text-white/40 uppercase tracking-widest">
                <MapPin className="w-3 h-3" /> {profile?.city || 'PRISHTINË'}
              </div>
            </div>

            <div className="h-40 w-full rounded-[1.5rem] overflow-hidden border border-white/5 relative">
               <RouteMap points={routePoints} />
            </div>

            <div className="grid grid-cols-2 gap-3">
              <Button onClick={handleSaveRun} disabled={isSaving} className="h-14 bg-white text-black rounded-2xl font-black uppercase text-[10px] tracking-widest">
                {isSaving ? <Loader2 className="w-4 h-4 animate-spin" /> : "RUAJ"}
              </Button>
              <Button variant="outline" className="h-14 border-white/10 rounded-2xl font-black uppercase text-[10px] tracking-widest" onClick={() => { setShowSummary(false); resetTrip(); }}>
                ANULO
              </Button>
            </div>
          </div>
        </DialogContent>
      </Dialog>

      <BottomNav />
    </div>
  );
}

